83	TEST_CASE("byte-level roundtrip via memcpy preserves all fields")
84	{
85	  hybrid_state_v1 src{};
86	  src.magic = HYBRID_STATE_MAGIC;
87	  src.version = HYBRID_STATE_VERSION;
88	  src.flags = HYBRID_FLAG_RV64 | HYBRID_FLAG_FP | HYBRID_FLAG_V;
89	  src.hart_id = 1;
90	  src.pc = 0x80001234ULL;
91	  src.priv = 3;  // M-mode
92	
93	  for (int i = 0; i < 32; ++i) {
94	    src.gpr[i] = 0xCAFE0000ULL + i;
95	    src.fpr[i] = 0xF00D0000ULL + i;
96	  }
97	  src.mstatus = 0xa00040080ULL;
98	  src.mepc    = 0x80002000ULL;
99	  src.mtvec   = 0x80000000ULL;
100	  src.satp    = 0x8000000000080000ULL;
101	  src.vstart  = 0;
102	  src.vtype   = 0xc0;
103	  src.vl      = 4;
104	  src.vlenb   = 16;
105	  src.vxsat   = 1;
106	  src.vxrm    = 2;
107	  src.vcsr    = 0x5;  // vxrm[2:1] | vxsat[0]
108	  for (size_t i = 0; i < sizeof(src.vreg); ++i) src.vreg[i] = (uint8_t) i;
109	
110	  alignas(hybrid_state_v1) unsigned char buf[sizeof(hybrid_state_v1)];
111	  std::memcpy(buf, &src, sizeof(src));
112	  hybrid_state_v1 dst{};
113	  std::memcpy(&dst, buf, sizeof(dst));
114	
115	  CHECK(dst.magic == HYBRID_STATE_MAGIC);
116	  CHECK(dst.version == HYBRID_STATE_VERSION);
117	  CHECK(dst.flags == src.flags);
118	  CHECK(dst.hart_id == 1);
119	  CHECK(dst.pc == 0x80001234ULL);
120	  CHECK(dst.priv == 3);
121	  for (int i = 0; i < 32; ++i) {
122	    CHECK(dst.gpr[i] == 0xCAFE0000ULL + i);
123	    CHECK(dst.fpr[i] == 0xF00D0000ULL + i);
124	  }
125	  CHECK(dst.mstatus == 0xa00040080ULL);
126	  CHECK(dst.mepc == 0x80002000ULL);
127	  CHECK(dst.mtvec == 0x80000000ULL);
128	  CHECK(dst.satp == 0x8000000000080000ULL);
129	  CHECK(dst.vtype == 0xc0);
130	  CHECK(dst.vl == 4);
131	  CHECK(dst.vlenb == 16);
132	  CHECK(dst.vxsat == 1);
133	  CHECK(dst.vxrm == 2);
134	  CHECK(dst.vcsr == 0x5);
135	  CHECK(std::memcmp(dst.vreg, src.vreg, sizeof(src.vreg)) == 0);
136	}
